BEGIN;

TRUNCATE submissions RESTART IDENTITY CASCADE;

SELECT setval('submissions_id_seq', (SELECT MAX(id) FROM submissions));

TRUNCATE milestones RESTART IDENTITY CASCADE;

SELECT setval('milestones_id_seq', (SELECT MAX(id) FROM milestones));

COMMIT;
